import React, { useState, useEffect, useRef, useCallback } from 'react';
import {
  Terminal as TerminalIcon,
  Plus,
  X,
  Maximize2,
  Minimize2,
  Copy,
  Download,
  RotateCcw,
  Wifi,
  WifiOff,
  AlertCircle,
  Loader2
} from 'lucide-react';

function Terminal({ devices }) {
  const [tabs, setTabs] = useState([]);
  const [activeTab, setActiveTab] = useState(null);
  const [commandInput, setCommandInput] = useState('');
  const [selectDeviceOpen, setSelectDeviceOpen] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [useSimulation, setUseSimulation] = useState({});

  const terminalRef = useRef(null);
  const inputRef = useRef(null);
  const wsRef = useRef({});

  useEffect(() => {
    if (terminalRef.current) {
      terminalRef.current.scrollTop = terminalRef.current.scrollHeight;
    }
  }, [tabs, activeTab]);

  useEffect(() => {
    return () => {
      Object.values(wsRef.current).forEach(ws => {
        if (ws && ws.close) ws.close();
      });
    };
  }, []);

  const simulateTerminal = (command, device) => {
    const cmd = command.toLowerCase().trim();
    const responses = {
      'display version': 'Huawei Versatile Routing Platform Software\nVersion 8.180\n' + (device.vendor || 'Huawei'),
      'display cpu': 'CPU utilization: 15%',
      'display memory': 'Memory: 2949 MB used',
      'help': 'Commands: display version, display cpu, display memory',
    };
    if (responses[cmd]) return responses[cmd];
    if (cmd === '') return '';
    return 'Unknown command. Type "help" for available commands.';
  };

  const createTab = useCallback((device) => {
    const tabId = device.id + '-' + Date.now();

    setTabs(prev => [...prev, {
      id: tabId,
      device,
      status: 'connecting',
      output: ['[CONNECTING] Connecting to ' + device.name + ' (' + device.ip + ':' + device.port + ')...'],
      commandHistory: [],
      historyIndex: -1,
    }]);
    setActiveTab(tabId);
    setSelectDeviceOpen(false);

    // Try WebSocket connection
    try {
      const wsUrl = (window.location.protocol === 'https:' ? 'wss://' : 'ws://') + window.location.host + '/ws/terminal/' + device.id + '/';
      const ws = new WebSocket(wsUrl);

      ws.onopen = () => {
        setTabs(prev => prev.map(tab => {
          if (tab.id !== tabId) return tab;
          return { ...tab, status: 'connected', output: [...tab.output, '[OK] Connected via WebSocket!'] };
        }));
        setUseSimulation(prev => ({ ...prev, [tabId]: false }));
      };

      ws.onmessage = (event) => {
        setTabs(prev => prev.map(tab => {
          if (tab.id !== tabId) return tab;
          return { ...tab, output: [...tab.output, event.data] };
        }));
      };

      ws.onclose = (event) => {
        setTabs(prev => prev.map(tab => {
          if (tab.id !== tabId) return tab;
          return { ...tab, status: 'disconnected', output: [...tab.output, '[DISCONNECTED] Code: ' + event.code] };
        }));
      };

      ws.onerror = () => {
        setUseSimulation(prev => ({ ...prev, [tabId]: true }));
        setTabs(prev => prev.map(tab => {
          if (tab.id !== tabId) return tab;
          return { ...tab, status: 'connected', output: [...tab.output, '[SIM] Simulation mode (WebSocket unavailable)'] };
        }));
      };

      wsRef.current[tabId] = ws;
    } catch (error) {
      console.error('WebSocket error:', error);
      setUseSimulation(prev => ({ ...prev, [tabId]: true }));
      setTabs(prev => prev.map(tab => {
        if (tab.id !== tabId) return tab;
        return { ...tab, status: 'connected', output: [...tab.output, '[SIM] Simulation mode'] };
      }));
    }
  }, []);

  const closeTab = (tabId) => {
    if (wsRef.current[tabId]) {
      wsRef.current[tabId].close();
      delete wsRef.current[tabId];
    }
    setTabs(prev => prev.filter(t => t.id !== tabId));
    if (activeTab === tabId) {
      const remaining = tabs.filter(t => t.id !== tabId);
      setActiveTab(remaining.length > 0 ? remaining[0].id : null);
    }
  };

  const executeCommand = (command) => {
    if (!activeTab) return;
    const activeTerminal = tabs.find(t => t.id === activeTab);
    if (!activeTerminal) return;

    const ws = wsRef.current[activeTab];
    if (useSimulation[activeTab] || !ws || ws.readyState !== WebSocket.OPEN) {
      const output = simulateTerminal(command, activeTerminal.device);
      setTabs(prev => prev.map(tab => {
        if (tab.id !== activeTab) return tab;
        return { ...tab, output: [...tab.output, '>' + command, output], commandHistory: [command, ...tab.commandHistory] };
      }));
    } else {
      ws.send(JSON.stringify({ type: 'input', data: command + '\n' }));
      setTabs(prev => prev.map(tab => {
        if (tab.id !== activeTab) return tab;
        return { ...tab, output: [...tab.output, '>' + command], commandHistory: [command, ...tab.commandHistory] };
      }));
    }
    setCommandInput('');
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter') executeCommand(commandInput);
  };

  const copyOutput = () => {
    const activeTerminal = tabs.find(t => t.id === activeTab);
    if (activeTerminal) {
      navigator.clipboard.writeText(activeTerminal.output.join('\n'));
    }
  };

  const clearTerminal = () => {
    setTabs(prev => prev.map(tab => tab.id === activeTab ? { ...tab, output: ['>'] } : tab));
  };

  const downloadOutput = () => {
    const activeTerminal = tabs.find(t => t.id === activeTab);
    if (activeTerminal) {
      const blob = new Blob([activeTerminal.output.join('\n')], { type: 'text/plain' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = 'terminal-' + activeTerminal.device.name + '.txt';
      a.click();
      URL.revokeObjectURL(url);
    }
  };

  const activeTerminal = tabs.find(t => t.id === activeTab);

  return (
    <div className={'space-y-4' + (isFullscreen ? ' fixed inset-0 z-50 bg-background p-4' : '')}>
      {/* Header */}
      <div className="flex flex-col sm:flex-row gap-4 justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Multi-Terminal SSH</h1>
          <p className="text-muted-foreground">Terminal multi-abas com auditoria</p>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setIsFullscreen(!isFullscreen)} className="p-2 border border-border rounded-lg hover:bg-secondary">
            {isFullscreen ? <Minimize2 className="h-4 w-4" /> : <Maximize2 className="h-4 w-4" />}
          </button>
          <button onClick={() => setSelectDeviceOpen(true)} className="px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary/90 flex items-center gap-2">
            <Plus className="h-4 w-4" /> Nova Conexão
          </button>
        </div>
      </div>

      {/* Terminal Tabs */}
      <div className="bg-card rounded-lg border border-border overflow-hidden">
        {/* Tab Headers */}
        <div className="flex items-center justify-between p-2 border-b border-border bg-secondary/30">
          <div className="flex items-center gap-2 overflow-x-auto">
            {tabs.map((tab) => (
              <div
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={'flex items-center gap-2 px-3 py-1.5 rounded-md cursor-pointer ' + (activeTab === tab.id ? 'bg-primary text-white' : 'bg-card hover:bg-secondary')}
              >
                {tab.status === 'connected' ? (
                  useSimulation[tab.id] ? <AlertCircle className="h-3 w-3 text-yellow-500" /> : <Wifi className="h-3 w-3 text-green-500" />
                ) : tab.status === 'connecting' ? (
                  <Loader2 className="h-3 w-3 text-yellow-500 animate-spin" />
                ) : (
                  <WifiOff className="h-3 w-3 text-red-500" />
                )}
                <span className="text-sm whitespace-nowrap">{tab.device.name}</span>
                <button onClick={(e) => { e.stopPropagation(); closeTab(tab.id); }} className="p-0.5 hover:bg-white/20 rounded">
                  <X className="h-3 w-3" />
                </button>
              </div>
            ))}
            {tabs.length === 0 && <span className="text-muted-foreground text-sm px-2">Nenhuma conexão ativa</span>}
          </div>
          {activeTab && (
            <div className="flex gap-1">
              <button onClick={copyOutput} className="p-1.5 hover:bg-secondary rounded" title="Copiar"><Copy className="h-4 w-4" /></button>
              <button onClick={downloadOutput} className="p-1.5 hover:bg-secondary rounded" title="Download"><Download className="h-4 w-4" /></button>
              <button onClick={clearTerminal} className="p-1.5 hover:bg-secondary rounded" title="Limpar"><RotateCcw className="h-4 w-4" /></button>
            </div>
          )}
        </div>

        {/* Terminal Content */}
        {activeTerminal ? (
          <div className="bg-black rounded-b-lg" style={{ height: isFullscreen ? 'calc(100vh - 12rem)' : '500px' }} onClick={() => inputRef.current && inputRef.current.focus()}>
            <div ref={terminalRef} className="h-full overflow-y-auto p-4 font-mono text-sm text-green-400">
              {activeTerminal.output.map((line, i) => <div key={i}>{line}</div>)}
            </div>
            <div className="flex items-center p-2 border-t border-gray-800">
              <span className="text-green-400 font-mono mr-2">{activeTerminal.device.name}&gt;</span>
              <input
                ref={inputRef}
                type="text"
                value={commandInput}
                onChange={(e) => setCommandInput(e.target.value)}
                onKeyDown={handleKeyDown}
                className="flex-1 bg-transparent border-none outline-none text-green-400 font-mono text-sm"
                placeholder="Digite um comando..."
                autoFocus
              />
              {useSimulation[activeTab] && (
                <span className="px-2 py-0.5 text-xs bg-yellow-500/20 text-yellow-500 rounded">SIM</span>
              )}
            </div>
          </div>
        ) : (
          <div className="h-[500px] flex items-center justify-center bg-black/5 rounded-b-lg">
            <div className="text-center text-muted-foreground">
              <TerminalIcon className="h-16 w-16 mx-auto mb-4 opacity-50" />
              <p className="text-lg">Nenhuma conexão ativa</p>
              <p className="text-sm">Clique em "Nova Conexão" para começar</p>
            </div>
          </div>
        )}
      </div>

      {/* Quick Commands */}
      {activeTerminal && (
        <div className="bg-card rounded-lg border border-border p-4">
          <h3 className="text-sm font-semibold mb-2">Comandos Rápidos</h3>
          <div className="flex flex-wrap gap-2">
            {['display version', 'display cpu', 'display memory', 'help'].map((cmd) => (
              <button key={cmd} onClick={() => executeCommand(cmd)} className="px-3 py-1 bg-secondary border border-border rounded text-xs font-mono hover:bg-primary hover:text-white">
                {cmd}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Device Selection Modal */}
      {selectDeviceOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
          <div className="bg-card rounded-lg border border-border w-full max-w-md max-h-[80vh] overflow-hidden">
            <div className="p-4 border-b border-border flex items-center justify-between">
              <h2 className="text-lg font-semibold">Selecionar Dispositivo</h2>
              <button onClick={() => setSelectDeviceOpen(false)} className="p-1 hover:bg-secondary rounded">
                <X className="h-5 w-5" />
              </button>
            </div>
            <div className="p-2 overflow-y-auto max-h-96">
              {devices.map((device) => (
                <div
                  key={device.id}
                  onClick={() => createTab(device)}
                  className="flex items-center justify-between p-3 hover:bg-secondary rounded-lg cursor-pointer"
                >
                  <div className="flex items-center gap-3">
                    <Wifi className="h-5 w-5 text-green-500" />
                    <div>
                      <div className="font-medium">{device.name}</div>
                      <div className="text-sm text-muted-foreground">{device.ip}:{device.port}</div>
                    </div>
                  </div>
                  <span className="px-2 py-1 bg-primary/20 text-primary rounded text-xs capitalize">{device.device_type}</span>
                </div>
              ))}
              {devices.length === 0 && (
                <div className="p-8 text-center text-muted-foreground">Nenhum dispositivo disponível</div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default Terminal;
